#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";skip=false;serial=emulator-5554;from_code=9000;from_name=0.9.0;to_code=10000;to_name=1.0.0;while (($#));do case "$1" in --skip-build)skip=true;shift;;--serial)serial="${2:?}";shift 2;;--from-version-code)from_code="${2:?}";shift 2;;--from-version-name)from_name="${2:?}";shift 2;;--to-version-code)to_code="${2:?}";shift 2;;--to-version-name)to_name="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;old="$ARCHPHENE_ROOT/tooling/build/manager-self-update/manager-$from_name.apk";latest="$ARCHPHENE_ROOT/prototypes/linux-app-manager-stub/out-linux/archphene.apk";if [[ "$skip" == false ]];then "$ARCHPHENE_SCRIPTS_DIR/build-install-linux-manager-stub.sh" --skip-install --version-code "$from_code" --version-name "$from_name";mkdir -p "$(dirname "$old")";cp "$latest" "$old";"$ARCHPHENE_SCRIPTS_DIR/build-install-linux-manager-stub.sh" --skip-install --version-code "$to_code" --version-name "$to_name";fi;archphene_require_file "$old";archphene_require_file "$latest";archphene_test_init "$serial";package=org.archpheneos.manager;archphene_adb_run uninstall "$package" >/dev/null 2>&1 || true;archphene_adb_run install "$old" >/dev/null;archphene_adb_run push "$latest" /data/local/tmp/manager-self-update.apk >/dev/null;archphene_adb_run shell run-as "$package" cp /data/local/tmp/manager-self-update.apk cache/manager-self-update.apk;hash="$(archphene_sha256_file "$latest")";archphene_adb_run shell appops set "$package" REQUEST_INSTALL_PACKAGES allow;archphene_adb_run shell am start -W -n "$package/.MainActivity" --es archphene_test_apk_url "file:///data/user/0/$package/cache/manager-self-update.apk" --es archphene_test_apk_sha256 "$hash" --es archphene_test_apk_package "$package" >/dev/null;archphene_wait_ui_text Update manager-self-update 30;archphene_tap_text "$ARCHPHENE_UI" Update;deadline=$((SECONDS+30));while ((SECONDS<deadline));do dump="$(archphene_adb_run shell dumpsys package "$package")";[[ "$dump" == *"versionCode=$to_code"* && "$dump" == *"versionName=$to_name"* ]] && break;sleep 1;done;[[ "$dump" == *"versionCode=$to_code"* ]] || archphene_die 'self-update did not install';archphene_note "Manager self-update passed: $from_name -> $to_name."
